import{bQ as d,aL as e,u as o,G as c}from"./chunks/framework.D06dwy5q.js";const a="/kb/assets/nacos-namespace-ops-test-annotated-current.DqC66AgO.png",s="/kb/assets/nacos-config-editor-fields-ops-demo-annotated-current.CqZzlehU.png",p="/kb/assets/nacos-config-editor-content-publish-ops-demo-annotated-current.BPFhMY24.png",i="/kb/assets/nacos-config-list-ops-demo-annotated-current.CXD5oupL.png",r="/kb/assets/nacos-config-detail-ops-demo-annotated-current.VQAGM2Ut.png",l="/kb/assets/nacos-config-history-ops-demo-annotated-current.BTSflyns.png",n="/kb/assets/nacos-service-list-ops-demo-annotated-current.CjWJRB6l.png",h="/kb/assets/nacos-service-detail-ops-demo-annotated-current.CMWQBEdd.png",b="/kb/assets/nacos-cluster-management-annotated-current.T6nO756f.png",A=JSON.parse('{"title":"Nacos 平台操作","description":"","frontmatter":{},"headers":[],"relativePath":"07.服务注册与配置中心/06-Nacos平台操作.md","filePath":"07.服务注册与配置中心/06-Nacos平台操作.md","lastUpdated":null}'),g={name:"07.服务注册与配置中心/06-Nacos平台操作.md"};function u(m,t,k,y,_,D){return e(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="nacos-平台操作" tabindex="-1">Nacos 平台操作 <a class="header-anchor" href="#nacos-平台操作" aria-label="Permalink to &quot;Nacos 平台操作&quot;">​</a></h1><p>Nacos 控制台主要用于确认配置、服务、命名空间和集群节点的当前状态。命令行和客户端 SDK 更适合做自动化验证，控制台更适合人工核对字段、查看历史版本、确认实例健康状态，以及在配置出问题时快速找到回滚入口。</p><h2 id="一、控制台入口" tabindex="-1">一、控制台入口 <a class="header-anchor" href="#一、控制台入口" aria-label="Permalink to &quot;一、控制台入口&quot;">​</a></h2><p>Nacos 3.x 控制台入口：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.10.11:8080/next/</span></span></code></pre></div><p>服务端 API 入口：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.10.11:8848/nacos/</span></span></code></pre></div><p><code>8080</code> 和 <code>8848</code> 是两类入口。<code>8080/next/</code> 是浏览器控制台，<code>8848/nacos/</code> 面向客户端注册、配置读取和服务端 API。旧资料里常见的 <code>8848/nacos</code> 控制台入口在 3.x 已经不适用，访问 <code>8848</code> 时会看到控制台默认端口为 <code>8080</code> 的提示。</p><p>实验环境账号：</p><table tabindex="0"><thead><tr><th>项目</th><th>值</th></tr></thead><tbody><tr><td>用户名</td><td><code>nacos</code></td></tr><tr><td>密码</td><td><code>nacos</code></td></tr></tbody></table><p>登录后如果页面长时间停留在空列表，可以重新登录后刷新。Nacos 3.x 控制台是前端单页应用，浏览器里残留的过期 token 有时会让页面看起来像&quot;没有数据&quot;，接口侧实际已经有配置或服务。</p><h2 id="二、命名空间" tabindex="-1">二、命名空间 <a class="header-anchor" href="#二、命名空间" aria-label="Permalink to &quot;二、命名空间&quot;">​</a></h2><p>命名空间用于隔离不同环境或不同业务域的配置与服务。同一个 <code>Data ID</code>、同一个服务名，在不同命名空间里可以同时存在，互不影响。排查配置不生效、服务查不到时，命名空间通常和 <code>Group</code>、<code>Data ID</code>、<code>serviceName</code> 一起核对。</p><p>操作路径：</p><p><code>平台管理 -&gt; 命名空间 -&gt; 新建命名空间</code></p><p>操作步骤：</p><ol><li>进入 <code>平台管理 -&gt; 命名空间</code>。</li><li>点击右上角 <code>新建命名空间</code>。</li><li>填写命名空间 ID、命名空间名称和描述。</li><li>保存后回到命名空间列表，确认新命名空间出现在列表里。</li></ol><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>填写值</th><th>说明</th></tr></thead><tbody><tr><td>命名空间 ID</td><td><code>ops-test</code></td><td>客户端配置里使用的 namespace 标识</td></tr><tr><td>命名空间名称</td><td><code>ops-test</code></td><td>控制台显示名称</td></tr><tr><td>描述</td><td><code>运维测试命名空间</code></td><td>用来说明这个空间的用途</td></tr></tbody></table><p>保存后验证：</p><p><code>平台管理 -&gt; 命名空间</code> 列表里能看到 <code>ops-test</code>，配置数为 <code>1</code>。配置数不是健康检查，只表示该命名空间下当前有多少条配置记录。</p><p><img src="'+a+'" alt="Nacos 命名空间列表"></p><p>排错入口：</p><p><code>配置管理 -&gt; 配置列表</code> 或 <code>服务管理 -&gt; 服务列表</code> 查不到对象时，先看控制台顶部命名空间下拉框。页面当前是 <code>public</code>，对象在 <code>ops-test</code>，列表自然为空。</p><h2 id="三、发布配置" tabindex="-1">三、发布配置 <a class="header-anchor" href="#三、发布配置" aria-label="Permalink to &quot;三、发布配置&quot;">​</a></h2><p>配置管理的核心标识是 <code>Namespace + Data ID + Group</code>。<code>Data ID</code> 通常对应一份配置文件或配置项名称，<code>Group</code> 用来做进一步分组，命名空间做环境隔离。应用读不到配置时，通常就是这三段中的某一段和应用侧配置不一致。</p><p>操作路径：</p><p><code>配置管理 -&gt; 配置列表 -&gt; 新建配置</code></p><p>已有配置重新发布时，入口是：</p><p><code>配置管理 -&gt; 配置列表 -&gt; 编辑</code></p><p>操作步骤：</p><ol><li>进入 <code>配置管理 -&gt; 配置列表</code>。</li><li>首次创建点击右上角 <code>新建配置</code>；修改已有配置时，在配置行右侧点击 <code>编辑</code>。</li><li>填写或核对 <code>Data ID</code>、<code>Group</code>、描述、归属应用、标签和配置格式。</li><li>点击 <code>发布</code>。</li><li>回到配置列表，按 <code>Data ID</code> 或 <code>Group</code> 搜索确认配置存在。</li></ol><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>填写值</th><th>说明</th></tr></thead><tbody><tr><td>命名空间</td><td><code>public</code></td><td>当前控制台顶部选择的命名空间</td></tr><tr><td>Data ID</td><td><code>ops-demo.yaml</code></td><td>应用读取配置时要指定的配置名</td></tr><tr><td>Group</td><td><code>DEFAULT_GROUP</code></td><td>默认分组，客户端也要使用同一个值</td></tr><tr><td>配置格式</td><td><code>YAML</code></td><td>控制台编辑器按 YAML 显示，应用侧也按 YAML 解析</td></tr><tr><td>归属应用</td><td><code>ops-demo</code></td><td>便于在控制台按应用筛选</td></tr><tr><td>标签</td><td><code>lab,nacos</code></td><td>辅助检索，不参与客户端唯一定位</td></tr><tr><td>配置内容</td><td>见下面 YAML</td><td>应用实际读取的配置文本</td></tr></tbody></table><p>配置字段页里，<code>Data ID</code> 和 <code>Group</code> 是应用读取配置时最关键的两个标识；描述、归属应用和标签主要服务于控制台检索和管理。已有配置进入编辑页时，<code>Data ID</code> 和 <code>Group</code> 会显示为不可编辑状态，这可以减少误改配置标识造成的读取异常。</p><p><img src="'+s+`" alt="Nacos 配置字段填写"></p><p>配置内容：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8081</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">feature</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  gray</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5000</span></span></code></pre></div><p>配置内容写在正式发布页签里。<code>Beta</code> 页签用于灰度配置发布，普通配置更新保留在 <code>正式</code> 页签即可。内容确认后点击右下角 <code>发布</code>，Nacos 会写入配置表并生成历史版本记录。</p><p><img src="`+p+'" alt="Nacos 配置内容发布"></p><p>发布后验证：</p><p><code>配置管理 -&gt; 配置列表</code> 中确认 <code>ops-demo.yaml</code>、<code>DEFAULT_GROUP</code>、<code>YAML</code>、<code>ops-demo</code> 四个字段和预期一致。</p><p><img src="'+i+'" alt="Nacos 配置列表"></p><p>排错入口：</p><p>配置列表查不到时，按顺序核对顶部命名空间、<code>Data ID</code>、<code>Group</code> 和搜索模式。模糊搜索和精确搜索的结果可能不同，排查时更适合用精确搜索。</p><h2 id="四、查看配置详情" tabindex="-1">四、查看配置详情 <a class="header-anchor" href="#四、查看配置详情" aria-label="Permalink to &quot;四、查看配置详情&quot;">​</a></h2><p>操作路径：</p><p><code>配置管理 -&gt; 配置列表 -&gt; 详情</code></p><p>操作步骤：</p><ol><li>在配置列表找到 <code>ops-demo.yaml</code>。</li><li>点击右侧 <code>详情</code>。</li><li>核对基本信息、标签、描述、创建时间、更新时间和配置内容。</li></ol><p>详情页重点看这些字段：</p><table tabindex="0"><thead><tr><th>区域</th><th>作用</th></tr></thead><tbody><tr><td><code>Data ID</code> / <code>Group</code></td><td>确认应用侧读取标识</td></tr><tr><td>配置格式</td><td>确认应用侧解析方式</td></tr><tr><td>归属应用 / 标签</td><td>辅助检索和管理</td></tr><tr><td>创建时间 / 更新时间</td><td>判断配置是否刚被改过</td></tr><tr><td>配置内容</td><td>应用最终读取的文本</td></tr></tbody></table><p><img src="'+r+'" alt="Nacos 配置详情"></p><p>排错入口：</p><p>应用报 YAML 解析异常时，控制台能保存并不代表应用一定能解析。详情页只证明文本已经保存；还要把内容复制到应用使用的解析器或本地校验工具里确认格式。常见问题是缩进层级错、冒号后缺空格、列表缩进和应用配置类不匹配。</p><h2 id="五、历史版本和回滚" tabindex="-1">五、历史版本和回滚 <a class="header-anchor" href="#五、历史版本和回滚" aria-label="Permalink to &quot;五、历史版本和回滚&quot;">​</a></h2><p>历史版本用于确认配置改动记录。发布后接口异常、开关状态不符合预期、应用启动失败时，历史版本页可以看到最近两次变更，并进入详情、回滚或对比。</p><p>操作路径：</p><p><code>配置管理 -&gt; 历史版本</code></p><p>操作步骤：</p><ol><li>进入 <code>配置管理 -&gt; 历史版本</code>。</li><li>在 <code>Data ID</code> 填写 <code>ops-demo.yaml</code>。</li><li>在 <code>Group</code> 填写 <code>DEFAULT_GROUP</code>。</li><li>点击 <code>搜索</code>。</li><li>核对发布时间、操作人和右侧 <code>详情</code>、<code>回滚</code>、<code>对比</code> 入口。</li></ol><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>填写值</th><th>说明</th></tr></thead><tbody><tr><td>Data ID</td><td><code>ops-demo.yaml</code></td><td>要查询的配置</td></tr><tr><td>Group</td><td><code>DEFAULT_GROUP</code></td><td>要查询的分组</td></tr></tbody></table><p>查询后验证：</p><p>历史版本列表里能看到两条 <code>ops-demo.yaml</code> 的正式发布记录，操作人为 <code>nacos</code>。</p><p><img src="'+l+'" alt="Nacos 配置历史版本"></p><p>排错入口：</p><p>配置发布后业务异常时，历史版本页先看最近一次更新时间是否和变更窗口吻合，再打开 <code>对比</code> 看改动内容。回滚前还要确认当前应用是否已经读取到新配置；如果应用本身没有启用动态刷新，回滚 Nacos 配置后应用进程里仍可能保留旧值。</p><h2 id="六、服务列表" tabindex="-1">六、服务列表 <a class="header-anchor" href="#六、服务列表" aria-label="Permalink to &quot;六、服务列表&quot;">​</a></h2><p>服务发现的控制台验证分两层：服务列表看一个服务名下面有多少实例，服务详情看每个实例的 IP、端口、权重、健康状态和元数据。服务是否&quot;存在&quot;和实例是否&quot;健康&quot;不是一回事。</p><p>操作路径：</p><p><code>服务管理 -&gt; 服务列表</code></p><p>操作步骤：</p><ol><li>进入 <code>服务管理 -&gt; 服务列表</code>。</li><li>在 <code>服务名</code> 输入 <code>ops-demo-service</code>。</li><li><code>分组名</code> 填写 <code>DEFAULT_GROUP</code>。</li><li>点击 <code>搜索</code>。</li><li>核对 <code>IP 数</code> 和 <code>健康实例数</code>。</li></ol><p>字段含义：</p><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>服务名</td><td><code>ops-demo-service</code></td><td>调用方按这个名字发现实例</td></tr><tr><td>分组名</td><td><code>DEFAULT_GROUP</code></td><td>服务分组，客户端也要一致</td></tr><tr><td>集群数</td><td><code>1</code></td><td>该服务下有 1 个集群分组</td></tr><tr><td>IP 数</td><td><code>2</code></td><td>当前注册了 2 个实例</td></tr><tr><td>健康实例数</td><td><code>2</code></td><td>2 个实例健康检查通过</td></tr></tbody></table><p><img src="'+n+'" alt="Nacos 服务列表"></p><p>排错入口：</p><p><code>IP 数</code> 大于 0 但 <code>健康实例数</code> 为 0 时，说明注册记录还在，但 Nacos 健康检查没有通过。这个时候继续点 <code>详情</code> 看实例 IP、端口、健康状态和元数据，再到实例所在机器确认端口是否真的监听。</p><h2 id="七、服务实例详情" tabindex="-1">七、服务实例详情 <a class="header-anchor" href="#七、服务实例详情" aria-label="Permalink to &quot;七、服务实例详情&quot;">​</a></h2><p>操作路径：</p><p><code>服务管理 -&gt; 服务列表 -&gt; 详情</code></p><p>操作步骤：</p><ol><li>在服务列表找到 <code>ops-demo-service</code>。</li><li>点击右侧 <code>详情</code>。</li><li>查看服务基本信息、集群名称和实例列表。</li><li>核对每个实例的 IP、端口、临时标记、权重、健康状态和元数据。</li></ol><p>实例字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>IP</td><td><code>192.168.10.12</code> / <code>192.168.10.13</code></td><td>被调用的实例地址</td></tr><tr><td>端口</td><td><code>18080</code></td><td>被调用的实例端口</td></tr><tr><td>临时</td><td><code>false</code></td><td>当前示例为持久实例</td></tr><tr><td>权重</td><td><code>1</code> / <code>0.5</code></td><td>客户端负载均衡时可能使用</td></tr><tr><td>健康</td><td><code>健康</code></td><td>健康检查通过</td></tr><tr><td>元数据</td><td><code>version=v1</code>、<code>version=v2</code>、<code>role=provider</code></td><td>灰度、路由或筛选时常用</td></tr></tbody></table><p><img src="'+h+'" alt="Nacos 服务实例详情"></p><p>排错入口：</p><p>实例不健康时，从三个位置对比：控制台实例详情、实例所在机器端口、Nacos 服务端接口返回。比如当前示例依赖 <code>192.168.10.12:18080</code> 和 <code>192.168.10.13:18080</code> 有真实服务监听；端口没开时，实例会保留在列表里，但健康状态会变成不健康。</p><h2 id="八、集群节点" tabindex="-1">八、集群节点 <a class="header-anchor" href="#八、集群节点" aria-label="Permalink to &quot;八、集群节点&quot;">​</a></h2><p>集群管理页面用于确认 Nacos 服务层是否按预期组成集群。它不代表 MySQL 高可用，也不代表业务实例健康，只说明 Nacos 节点之间的服务层状态。</p><p>操作路径：</p><p><code>平台管理 -&gt; 集群管理</code></p><p>操作步骤：</p><ol><li>进入 <code>平台管理 -&gt; 集群管理</code>。</li><li>查看节点地址、IP、端口和状态。</li><li>确认节点数量和 <code>cluster.conf</code> 一致。</li><li>确认三台节点状态都是 <code>运行中</code>。</li></ol><p>实验环境节点：</p><table tabindex="0"><thead><tr><th>节点地址</th><th>IP</th><th>端口</th><th>状态</th></tr></thead><tbody><tr><td><code>192.168.10.11:8848</code></td><td><code>192.168.10.11</code></td><td><code>8848</code></td><td><code>运行中</code></td></tr><tr><td><code>192.168.10.12:8848</code></td><td><code>192.168.10.12</code></td><td><code>8848</code></td><td><code>运行中</code></td></tr><tr><td><code>192.168.10.13:8848</code></td><td><code>192.168.10.13</code></td><td><code>8848</code></td><td><code>运行中</code></td></tr></tbody></table><p><img src="'+b+'" alt="Nacos 集群节点"></p><p>排错入口：</p><p>集群节点少一台时，对比三台机器的 <code>/opt/nacos/conf/cluster.conf</code>、端口监听和节点间通信端口。<code>cluster.conf</code> 写的是 <code>8848</code>，不是控制台 <code>8080</code>。控制台能登录不代表 <code>8848</code>、<code>9848</code>、<code>9849</code>、<code>7848</code> 都已经互通。</p><h2 id="九、ai-注册中心" tabindex="-1">九、AI 注册中心 <a class="header-anchor" href="#九、ai-注册中心" aria-label="Permalink to &quot;九、AI 注册中心&quot;">​</a></h2><p>Nacos 3.x 控制台里的 AI 注册中心包含 Skill、Prompt、Agent、AgentSpec、MCP 等对象。它更像 AI 应用对象的注册与发现入口，把这些对象纳入 Nacos 的管理模型中。</p><table tabindex="0"><thead><tr><th>模块</th><th>作用</th></tr></thead><tbody><tr><td>Skill 管理</td><td>管理可复用能力描述</td></tr><tr><td>Prompt 管理</td><td>管理 Prompt 模板</td></tr><tr><td>Agent 管理</td><td>管理 Agent 描述和发现信息</td></tr><tr><td>AgentSpec 管理</td><td>管理 Agent 规范描述</td></tr><tr><td>MCP 管理</td><td>管理 MCP 服务信息</td></tr></tbody></table><p>它不是 Linux 进程管理器，也不是负责启动、停止 Agent 的平台。Agent 怎么运行、怎么调用模型、怎么编排任务，仍然由具体 Agent 框架和运行环境负责。Nacos 这里更接近注册、发现和元数据管理。</p>',104)])])}const x=d(g,[["render",u]]);export{A as __pageData,x as default};
